        return abs(xi - xj) + abs(yi - yj)

    def dist2(xi, yi, xj, yj):
        return 2 * max(abs(xi - xj), abs(yi - yj))

    x0, y0, ax, ay, bx, by = inp(int)
    xs, ys, t = inp(int)
    a = [(x0, y0)]
